import { NextResponse } from "next/server";
import { printfulFetch } from "../../../../lib/printful";

function normalizeVariant(variant: any) {
  const sync = variant?.sync_variant ?? {};
  const files = variant?.files ?? [];

  const color =
    sync.color ||
    variant.color ||
    sync.color_name ||
    null;

  const size =
    sync.size ||
    variant.size ||
    null;

  const image =
    sync.product?.image ||
    sync.image ||
    variant.image ||
    files.find((f: any) => f?.preview_url)?.preview_url ||
    files.find((f: any) => f?.url)?.url ||
    null;

  const retailPrice =
    variant.retail_price ||
    sync.retail_price ||
    null;

  return {
    id: variant.id ?? null,
    variant_id: variant.variant_id ?? null,
    name: sync.name || variant.name || null,
    sku: sync.sku || variant.sku || null,
    retail_price: retailPrice,
    currency: "USD",
    color,
    size,
    availability_status: sync.availability_status || null,
    image,
    files: files.map((file: any) => ({
      id: file.id ?? null,
      type: file.type ?? null,
      preview_url: file.preview_url ?? null,
      url: file.url ?? null,
      filename: file.filename ?? null,
    })),
  };
}

export async function GET(
  _: Request,
  { params }: { params: { id: string } }
) {
  try {
    const id = params.id;

    if (!id) {
      return NextResponse.json(
        { ok: false, error: "Falta el id del producto" },
        { status: 400 }
      );
    }

    const data = await printfulFetch(`/store/products/${id}`);
    const raw = data?.result ?? data;

    const syncProduct = raw?.sync_product ?? {};
    const syncVariants = raw?.sync_variants ?? [];

    const product = {
      id: syncProduct.id ?? raw?.id ?? null,
      external_id: syncProduct.external_id ?? raw?.external_id ?? null,
      name: syncProduct.name ?? raw?.name ?? null,
      thumbnail_url: syncProduct.thumbnail_url ?? raw?.thumbnail_url ?? null,
      is_ignored: syncProduct.is_ignored ?? raw?.is_ignored ?? false,
      variants_count: syncVariants.length,
      variants: syncVariants.map(normalizeVariant),
    };

    return NextResponse.json({
      ok: true,
      product,
    });
  } catch (error) {
    return NextResponse.json(
      {
        ok: false,
        error:
          error instanceof Error
            ? error.message
            : "Error al leer el producto en Printful",
      },
      { status: 500 }
    );
  }
}